spec.expr:
group by (namespace, container, image) (
  changes(
    count by (namespace, container, image) (
      kube_pod_container_info{namespace=~"$namespace"}
    )[2m:30s]
  ) > 0
)

max by (pod) (
  process_open_fds{namespace=~"$namespace", app_type=~"$app_type"}
  /
  process_max_fds{namespace=~"$namespace", app_type=~"$app_type"}
) * 100
